def retrieve_by_date_range(
    user_id: str,
    after:  str,   # ISO date, e.g. "2025-01-01"
    before: str,   # ISO date, e.g. "2025-01-31"
) -> list[Episode]:
    return [
        e for e in load_all_episodes(user_id)
        if after <= e.timestamp[:10] <= before
    ]

def retrieve_by_topic(
    user_id: str,
    topic: str,
    top_k: int = 10,
) -> list[Episode]:
    topic_lower = topic.lower()
    matches = [
        e for e in load_all_episodes(user_id)
        if topic_lower in [t.lower() for t in e.topics]
        or topic_lower in e.summary.lower()
    ]
    return sorted(matches, key=lambda e: e.importance, reverse=True)[:top_k]

def build_episode_context(episodes: list[Episode]) -> str:
    """Format retrieved episodes for prompt injection."""
    if not episodes:
        return ""
    lines = ["[RELEVANT PAST EPISODES]"]
    for ep in episodes:
        lines.append(ep.to_recall_text())
    return "\n".join(lines)

def link_episodes(
    source_id: str,
    target_id: str,
    user_id: str,
) -> None:
    """Add a bidirectional link between two episodes."""
    user_dir = EPISODE_DIR / user_id
    for ep_id in (source_id, target_id):
        other = target_id if ep_id == source_id else source_id
        matches = list(user_dir.glob(f"*{ep_id[:8]}*.json"))
        if not matches:
            continue
        data = json.loads(matches[0].read_text())
        if other not in data.get("related_ids", []):
            data.setdefault("related_ids", []).append(other)
            matches[0].write_text(json.dumps(data, indent=2))

def get_related_episodes(episode_id: str, user_id: str) -> list[Episode]:
    user_dir = EPISODE_DIR / user_id
    matches  = list(user_dir.glob(f"*{episode_id[:8]}*.json"))
    if not matches:
        return []
    data = json.loads(matches[0].read_text())
    related = []
    for rel_id in data.get("related_ids", []):
        rel_matches = list(user_dir.glob(f"*{rel_id[:8]}*.json"))
        if rel_matches:
            related.append(Episode(**json.loads(rel_matches[0].read_text())))
    return related

def compute_importance(
    summary: str,
    outcome: str,
    topics: list[str],
    turn_count: int = 1,
) -> float:
    """
    Heuristic importance score in [0, 1].
    Tune thresholds based on domain.
    """
    score = 0.3  # baseline

    # Outcome signals value
    high_value_words = {"decided", "shipped", "fixed", "resolved", "completed", "agreed"}
    if any(w in outcome.lower() for w in high_value_words):
        score += 0.3

    # Multiple topics → cross-cutting concern
    if len(topics) >= 3:
        score += 0.1

    # Longer exchanges tend to be more substantive
    if turn_count >= 5:
        score += 0.1

    # Specific high-priority topic tags
    priority_topics = {"decision", "bug", "security", "milestone", "architecture"}
    if priority_topics & set(t.lower() for t in topics):
        score += 0.2

    return min(1.0, score)
